class Solution:
    def longestDecomposition(self, text: str) -> int:
        n = len(text)
        i, j, ans = 0, n - 1, 0
        while i < j:
            if text[i] == text[j]:
                i += 1
                j -= 1
                ans += 2
            else:
                break
        return ans + (i == j)
